export function icon(name, opts = {}) {
  const { size = 18, active = false, cls = '' } = opts;
  const g = ICONS[name] || ICONS.file;
  const b = active ? g.b : g.o;
  const span = document.createElement('span');
  span.className = 'icm-icon' + (cls ? ' ' + cls : '');
  span.innerHTML = `<svg width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" aria-hidden="true">${b}</svg>`;
  return span;
}
